#include<bits/stdc++.h>
using namespace std;
void solve(){
    long long n,ans=0;
    cin>>n;
    int x=1;
    while(n>=1){
        if(x%2){
            long long ten=1;
            for(int i=1;i<=x;i++) ten*=10;
            long long w=n%10*7;
            while(w>9){
                long long lin=w;
                w=0;
                while(lin>=1){
                    w+=lin%10;
                    lin/=10;
                }
            }
            ans+=w;
            ans*=10;
            n/=10;
        }else{
             long long ten=1;
            for(int i=1;i<=x;i++) ten*=10;
            ans+=n%10;
            ans*=10;
            n/=10;
        }
        x++;
    }
    n=0;
    while(ans>=1){
        n+=ans%10;
        ans/=10;
    }
    if(n%8==0){
		cout<<"T\n";
	}else{
		cout<<"F\n";
	}

}
int main(){
    int t;
    cin>>t;
    while(t--){
        solve();
    }
    return 0;
}
